// // This module implements a GPIO controller with an 8-bit data register and a control signal. It allows reading and writing data through a clocked process. The control signal determines if we are in read or write mode. In read mode, the data from the input is stored in the data register. In write mode, the data register's contents are outputted. The data register should be reset to 0 when a reset signal is asserted.
module gpio_controller(  
    input wire clk,  
    input wire reset,  
    input wire control,  // 0 for read, 1 for write  
    input wire [7:0] data_in,  
    output reg [7:0] data_out  
);  
    reg [7:0] data_reg;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            data_reg <= 8'b0;  
            data_out <= 8'b0;  
        end else begin  
            if (control) begin  
                // Write mode  
                data_reg <= data_in;  
            end else begin  
                // Read mode  
                data_out <= data_reg;  
            end  
        end  
    end  
endmodule
